export const meta = {
  name: 'verify-compile-distribution-bullet',
  description: 'Adversarially verify the new confidence_distribution bullet in compile.md §4 against producer and consumer contract texts',
  phases: [
    { title: 'Verify', detail: 'three lenses: consumer contract, producer internal consistency, factual claims' },
  ],
}

const VERDICT = {
  type: 'object',
  properties: {
    contradictions: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          claim: { type: 'string', description: 'The claim in the new bullet that is wrong or contradicted' },
          evidence: { type: 'string', description: 'file:line + quoted text proving the contradiction' },
          severity: { type: 'string', enum: ['blocking', 'minor'] },
        },
        required: ['claim', 'evidence', 'severity'],
      },
    },
    verdict: { type: 'string', enum: ['pass', 'fail'] },
    notes: { type: 'string' },
  },
  required: ['contradictions', 'verdict'],
}

const NEW_BULLET = 'In /home/armel/Projects/OSS/bmad-module-skill-forge/src/skf-create-skill/references/compile.md section "### 4. Build metadata.json Content", a new bullet was just added (it begins with: "- Set `confidence_distribution` by binning **each documented export exactly once**"). Read the file to see its exact final text.'

phase('Verify')
const lenses = [
  {
    key: 'consumer-contract',
    prompt: `${NEW_BULLET}

Your lens: CONSUMER CONTRACT. Adversarially try to find any way the new bullet contradicts what the consumer actually enforces. Read:
- /home/armel/Projects/OSS/bmad-module-skill-forge/src/skf-test-skill/references/coverage-check.md — especially the stack-skill branch (~line 285), the reference-app branch (~line 287), and §4b item 5 (~line 300)
- /home/armel/Projects/OSS/bmad-module-skill-forge/src/skf-create-skill/references/validate.md line 240 (the producer-validate statement of the same invariant, merged in PR #441)

Check specifically: (a) does the sum invariant match ("must sum to stats.exports_documented")? (b) do the stack and reference-app carve-outs in the bullet say the same thing as coverage-check's branches (what is binned, what it sums to)? (c) is "coverage-check §4b" the correct section reference for the enforcement? (d) is the new bullet consistent with validate.md:240 (no divergence between the two producer-side statements)? Report any contradiction with file:line evidence. Default to pass only if you found none after actually reading all three texts.`,
  },
  {
    key: 'producer-internal',
    prompt: `${NEW_BULLET}

Your lens: PRODUCER INTERNAL CONSISTENCY. Adversarially try to find any way the new bullet contradicts other producer-side texts in skf-create-skill. Read:
- /home/armel/Projects/OSS/bmad-module-skill-forge/src/skf-create-skill/references/compile.md — the whole §4 and §1b (Signature Fidelity Rule, defines signature_source)
- /home/armel/Projects/OSS/bmad-module-skill-forge/src/skf-create-skill/assets/skill-sections.md — the metadata.json template (~line 213) and the evidence-report "Extraction Summary" section (~line 367, the "Confidence: T1={n}, T1-low={n}, T2={n}, T3={n}" line)
- /home/armel/Projects/OSS/bmad-module-skill-forge/src/skf-create-skill/assets/compile-assembly-rules.md — any reference-app or stack stats semantics

Check specifically: (a) the bullet says T2 annotation / T3 doc-item enrichment totals "belong in the evidence report's Extraction Summary, not in the distribution" — does the Extraction Summary template's "Confidence: T1={n}..." line make this directive ambiguous or contradictory (i.e., would an agent following the bullet now produce an Extraction Summary line that disagrees with confidence_distribution)? (b) does the tier-key mapping (T1→t1, T1-low→t1_low, T2→t2, T3→t3) match §1b's signature_source enum and the template keys? (c) does compile.md's §4 produce stack skills at all, or is "stack" handled by a different workflow such that the stack carve-out sentence is dead text here — check whether skf-create-skill ever sets skill_type "stack" (grep the skf-create-skill directory; also check if a separate src/skf-* workflow owns stacks). Report contradictions with file:line evidence; classify (c) as minor if the carve-out is merely harmless dead text that mirrors validate.md.`,
  },
  {
    key: 'claims-factcheck',
    prompt: `${NEW_BULLET}

Your lens: FACTUAL CLAIMS. Verify every checkable claim in the new bullet against the repo at /home/armel/Projects/OSS/bmad-module-skill-forge:
1. "provenance-map \`signature_source\` tier" — confirm provenance-map entries carry a signature_source field with values T1/T1-low/T2/T3 (compile.md §1b and §6, skill-sections.md provenance-map template).
2. "stats.exports_documented" — confirm that exact field path exists in the metadata template.
3. "skf-test-skill coverage-check §4b" — confirm coverage-check.md actually has a §4b containing the sum check.
4. "pattern_surfaces_documented" — confirm that field name is real (grep src/ for it).
5. The bullet's placement: confirm it sits inside the §4 bullet list of compile.md with correct markdown list syntax (single "- " bullet, consistent with neighbors), and confirm the file has no duplicated or broken text from the edit (read the surrounding 20 lines).
Also check: does anything in src/skf-quick-skill (or the quick-metadata render script scripts/) define confidence_distribution differently in a way this bullet would mislead? Report any false claim with evidence.`,
  },
]

const results = await parallel(lenses.map(l => () =>
  agent(l.prompt, { label: `verify:${l.key}`, phase: 'Verify', schema: VERDICT })
))

const flat = results.filter(Boolean)
const blocking = flat.flatMap(r => r.contradictions.filter(c => c.severity === 'blocking'))
const minor = flat.flatMap(r => r.contradictions.filter(c => c.severity === 'minor'))
log(`verdicts: ${flat.map(r => r.verdict).join(', ')} — ${blocking.length} blocking, ${minor.length} minor`)
return { verdicts: flat.map(r => r.verdict), blocking, minor, notes: flat.map(r => r.notes).filter(Boolean) }
